+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { hasTrait } from '../trait/trait';
+import { getStore } from '../trait/trait';
+import type { Predicate, QueryInstance } from './types';
+import type { World } from '../world';
+
+export function evaluatePredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: any[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        values.push(trait[$internal].get(getEntityId(entity), getStore(world, trait)));
+    }
+    return predicate.predicate(values);
+}
+
+export function resetPredicateStates(query: QueryInstance) {
+    for (const modifier of query.trackingPredicates) {
+        const states = query.predicateStates.get(modifier) ?? [];
+        query.predicateStates.set(modifier, states);
+        const predicate = (modifier as any).predicate as Predicate;
+        for (const entity of query.world[$internal].entityIndex.dense) {
+            states[getEntityId(entity)] = evaluatePredicate(query.world, entity, predicate);
+        }
+    }
+}
+
+export function checkPredicateTracking(world: World, query: QueryInstance, entity: Entity): boolean {
+    if (!query.check(world, entity)) return false;
+    const eid = getEntityId(entity);
+    for (const modifier of query.trackingPredicates) {
+        const predicate = (modifier as any).predicate as Predicate;
+        const current = evaluatePredicate(world, entity, predicate);
+        const previous = query.predicateStates.get(modifier)?.[eid] ?? false;
+        const type = modifier.type;
+        if (type.startsWith('added-') ? !(current && !previous) : type.startsWith('removed-') ? !(!current && previous) : current === previous) {
+            return false;
+        }
+    }
+    return true;
+}
